import { Link } from "react-router-dom";
import authService from "src/auth/auth.service";

export const tableUserConstant = (handleConfirmModal) => {
    return [
        {
            id: 1,
            name: "User Name",
            cell: (row) => {
                return (
                    <Link to={`/user/edit/${row?._id}`}>
                        <span className="sub">{row.name}</span>
                    </Link>
                );
            },
            sortable: true,
            reorder: true,
            style: {
                color: "#202124",
                fontSize: "14px",
                fontWeight: 500,
            },
        },
        {
            id: 2,
            name: "Email",
            selector: (row) => row.email,
            sortable: true,
            reorder: true,
        },
        {
            id: 3,
            name: "Permission",
            cell: (row) => {
                let output = [];
                let count = 0;
                row.permission && row.permission.map((data, index) => {
                        if (index < 1) {
                            output.push(data);
                        } else {
                            count = count + 1;
                        }
                    });
                if (count === 0) {
                    return output;
                } else {
                    output = output + ", +" + count;
                    return output;
                }
            },
            sortable: true,
            reorder: true,
        },
        {
            id: 4,
            name: "Delete",
            cell: (row) => {
                return <i className={"fa-regular fa-trash-can" + (row.status === "ENABLE" || !authService.getPermission("DELETE") ? " disable" : "")} onClick={(e) => { handleConfirmModal(row._id) }}></i>;
            },
            sortable: true,
            reorder: true,
        },
    ];
};
